 25	import InterfaceDrawer from './components/InterfaceDrawer/InterfaceDrawer';
 26	import NNStateEmptyState from './components/NNStateEmptyState';
 27	import StateRow from './components/StateRow';
 28	import StatusBox from './components/StatusBox';
 29	import useDrawerInterface from './hooks/useDrawerInterface';
 30	import useSelectedFilters from './hooks/useSelectedFilters';
 31	import useSortStates from './hooks/useSortStates';
 32	import useStateColumns, { COLUMN_NAME_ID } from './hooks/useStateColumns';
 33	import { useStateFilters, useStateSearchFilters } from './hooks/useStateFilters';
 34	
 35	import './states-list.scss';
 36	
 37	const StatesList: FC = () => {
 38	  const { t } = useNMStateTranslation();
 39	  const navigate = useNavigate();
 40	  const {
 41	    selectedInterfaceName,
 42	    selectedStateName,
 43	    selectedInterfaceType,
 44	    setSelectedInterfaceName,
 45	  } = useDrawerInterface();
 46	
 47	  const onClose = useCallback(() => {
 48	    setSelectedInterfaceName();
 49	  }, []);
 50	
 51	  const [expandAll, setExpandAll] = useState(false);
 52	
 53	  const [states, statesLoaded, statesError] = useK8sWatchResource<V1beta1NodeNetworkState[]>({
 54	    groupVersionKind: NodeNetworkStateModelGroupVersionKind,
 55	    isList: true,
 56	    namespaced: false,
 57	  });
 58	
 59	  const selectedState = states?.find((state) => state.metadata.name === selectedStateName);
 60	  const selectedInterface = selectedState?.status?.currentState?.interfaces?.find(
 61	    (iface) => iface.name === selectedInterfaceName && iface.type === selectedInterfaceType,
 62	  );
 63	
 64	  const { onPaginationChange, pagination } = usePagination();
 65	  const [columns, activeColumns] = useStateColumns();
 66	  const filters = useStateFilters();
 67	  const searchFilters = useStateSearchFilters();
 68	
 69	  const selectedFilters = useSelectedFilters();
 70	  const [data, filteredData, onFilterChange] = useListPageFilter(states, [
 71	    ...filters,
 72	    ...searchFilters,
 73	  ]);
 74	
 75	  const { sortedStates, nameSortParams } = useSortStates(filteredData);
 76	
 77	  const paginatedData = sortedStates.slice(pagination?.startIndex, pagination?.endIndex + 1);
 78	  return (
 79	    <>
 80	      <ListPageHeader title={t(NodeNetworkStateModel.label)}>
 81	        {!isEmpty(states) && (
 82	          <Button isInline variant="plain" onClick={() => navigate('/nmstate-topology')}>
 83	            <Icon>
 84	              <TopologyIcon />
 85	            </Icon>
 86	          </Button>
 87	        )}
 88	      </ListPageHeader>
 89	      <ListPageBody>
 90	        <StatusBox loaded={statesLoaded} error={statesError}>
 91	          <div className="nns-list-management-group">
 92	            <Flex>
 93	              <ListPageFilter
 94	                data={data}
 95	                loaded={statesLoaded}
 96	                rowFilters={filters}
 97	                rowSearchFilters={searchFilters}
 98	                hideLabelFilter
 99	                onFilterChange={(...args) => {
100	                  onFilterChange(...args);
101	                  onPaginationChange({
102	                    endIndex: pagination?.perPage,
103	                    page: 1,
104	                    perPage: pagination?.perPage,
105	                    startIndex: 0,
106	                  });
107	                }}
108	                columnLayout={{
109	                  columns: columns?.map(({ id, title, additional }) => ({
110	                    id,
111	                    title,
112	                    additional,
113	                  })),
114	                  id: NodeNetworkStateModelRef,
115	                  selectedColumns: new Set(activeColumns?.map((col) => col?.id)),
116	                  type: t('NodeNetworkState'),
117	                }}
118	              />
119	              <Button onClick={() => setExpandAll(!expandAll)}>
120	                {expandAll ? t('Collapse all') : t('Expand all')}
121	              </Button>
122	            </Flex>
123	            <Pagination
124	              onPerPageSelect={(_e, perPage, page, startIndex, endIndex) =>
125	                onPaginationChange({ endIndex, page, perPage, startIndex })
126	              }
127	              onSetPage={(_e, page, perPage, startIndex, endIndex) =>
128	                onPaginationChange({ endIndex, page, perPage, startIndex })
129	              }
130	              className="list-managment-group__pagination"
131	              itemCount={sortedStates?.length}
132	              page={pagination?.page}
133	              perPage={pagination?.perPage}
134	              perPageOptions={paginationDefaultValues}
135	            />
136	          </div>
137	
138	          {sortedStates?.length ? (
139	            <Table gridBreakPoint={TableGridBreakpoint.none} role="presentation">
140	              <Thead>
141	                <Tr>
142	                  {activeColumns.map((column) => (
143	                    <Th
144	                      key={column.id}
145	                      {...column?.props}
146	                      sort={column.id === COLUMN_NAME_ID ? nameSortParams : null}
147	                    >
148	                      {column.title}
149	                    </Th>
150	                  ))}
151	                </Tr>
152	              </Thead>
153	              {paginatedData.map((nnstate, index) => (
154	                <StateRow
155	                  key={nnstate?.metadata?.name}
156	                  obj={nnstate}
157	                  activeColumnIDs={new Set(activeColumns.map(({ id }) => id))}
158	                  rowData={{ rowIndex: index, selectedFilters, expandAll }}
159	                />
160	              ))}
161	            </Table>
162	          ) : (
163	            <NNStateEmptyState />
164	          )}
165	        </StatusBox>
166	      </ListPageBody>
167	      <InterfaceDrawer onClose={onClose} selectedInterface={selectedInterface} />
168	    </>
169	  );
170	};
171	
172	export default StatesList;

