123	              onSetPage={(_e, page, perPage, startIndex, endIndex) =>
124	                onPaginationChange({ endIndex, page, perPage, startIndex })
125	              }
126	              className="list-managment-group__pagination"
127	              itemCount={sortedStates?.length}
128	              page={pagination?.page}
129	              perPage={pagination?.perPage}
130	              perPageOptions={paginationDefaultValues}
131	            />
132	          </div>
133	
134	          {sortedStates?.length ? (
135	            <Table gridBreakPoint={TableGridBreakpoint.none} role="presentation">
136	              <Thead>
137	                <Tr>
138	                  {activeColumns.map((column) => (
139	                    <Th
140	                      key={column.id}
141	                      {...column?.props}
142	                      sort={column.id === COLUMN_NAME_ID ? nameSortParams : null}
143	                    >
144	                      {column.title}
145	                    </Th>
146	                  ))}
147	                </Tr>
148	              </Thead>
149	              {paginatedData.map((nnstate, index) => (
150	                <StateRow
151	                  key={nnstate?.metadata?.name}
152	                  obj={nnstate}
153	                  activeColumnIDs={new Set(activeColumns.map(({ id }) => id))}
154	                  rowData={{ rowIndex: index, selectedFilters, expandAll }}
155	                />
156	              ))}
157	            </Table>
158	          ) : (
159	            <NNStateEmptyState />
160	          )}
161	        </StatusBox>
162	      </ListPageBody>
163	      <InterfaceDrawer onClose={onClose} selectedInterface={selectedInterface} />
164	    </>
165	  );
166	};
